// Dedupe items by URL (normalized: strip trailing slash, query params utm_*, fbclid, gclid)
// Also dedupe by title-similarity (lowercase, trim, first 80 chars)

function normalizeUrl(u) {
  try {
    const parsed = new URL(u);
    // Strip tracking params
    ['utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'fbclid', 'gclid', 'mc_cid', 'mc_eid'].forEach(p => parsed.searchParams.delete(p));
    let clean = parsed.origin + parsed.pathname;
    if (parsed.search) clean += parsed.search;
    return clean.replace(/\/$/, '').toLowerCase();
  } catch (e) {
    return (u || '').toLowerCase().trim();
  }
}

const seenUrl = new Set();
const seenTitle = new Set();
const deduped = [];

for (const item of items) {
  const url = normalizeUrl(item.json.link);
  const titleKey = (item.json.title || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().substring(0, 80);

  if (seenUrl.has(url) || seenTitle.has(titleKey)) continue;
  seenUrl.add(url);
  seenTitle.add(titleKey);
  deduped.push(item);
}

return deduped;

